-- Delete cycle_history for test players
DELETE FROM cycle_history WHERE userId IN (
  SELECT id FROM users WHERE name IN ('N.Balaji', 'Ayush', 'BR')
);

-- Delete test players from users table
DELETE FROM users WHERE name IN ('N.Balaji', 'Ayush', 'BR');

-- Verify deletion
SELECT COUNT(*) as remaining_users FROM users WHERE name IN ('N.Balaji', 'Ayush', 'BR');

